#!/usr/bin/env python3
"""
gkq_gpu_binding.py  (ADDITIVE — does not modify the original .cu or server)

Genuinely runs the gnosis spectral-weight reconstruction kernel on the GPU
(GTX 1080 Ti / sm_61).

Why NVRTC instead of `nvcc -arch=sm_61 ... -shared`?
  The only CUDA *toolkit* installed on this box is CUDA 13.3 (Windows side),
  and CUDA 13 DROPPED Pascal/sm_61 (`nvcc fatal: Unsupported gpu architecture
  'sm_61'`). There is no nvcc and no host C/C++ compiler inside WSL2 either.
  BUT the user-space torch cu121 stack ships pip wheels with:
      nvidia/cuda_nvrtc/lib/libnvrtc.so.12      (CUDA 12.1 NVRTC -> supports sm_61)
      nvidia/cuda_runtime/lib/libcudart.so.12
  plus the WSL driver libcuda.so.1. NVRTC compiles CUDA C++ -> PTX at runtime,
  and the driver JITs PTX -> sm_61 SASS. This lets us run the ACTUAL kernel
  source (lifted verbatim from reconstruct-weights-gpu.cu, algorithm unchanged)
  on the 1080 Ti, with no toolkit and no host compiler.

The device kernel `reconstruct_weights_spectral` and the `dequantize_uint8`
helper below are copied byte-for-byte from
  open-source/gnosis/distributed-inference/reconstruct-weights-gpu.cu
The host marshalling reproduces what `extern "C" reconstruct_weights_host`
does (cudaMalloc/Memcpy/launch/Memcpy-back), via the CUDA Driver API.

Dequant-range marshalling note:
  The kernel dequantizes EVERY component as
      x = min + (q/255)*(max-min)
  The server's NumPy _reconstruct_layer uses an offset-128 signed scheme for
  U and Vt and an unsigned scheme for sigma:
      U,Vt:  x = ((q-128)/127)*max
      sigma: x = (q/255)*max
  To make the kernel's single formula reproduce the server's scheme EXACTLY we
  pass:
      U_min   = -128/127 * U_max ,  U_max_arg = U_max
      V_min   = -128/127 * V_max ,  V_max_arg = V_max
      sigma_min = 0.0            ,  sigma_max_arg = sigma_max
  Check (U): min + (q/255)*(max-min)
           = -128/127*M + (q/255)*(M + 128/127*M)
           = -128/127*M + (q/255)*(255/127*M)
           = ((q-128)/127)*M   ✓
"""

import os
import ctypes
import glob
import numpy as np

# ----------------------------------------------------------------------------
# Locate the user-space CUDA 12.1 libs (libnvrtc, libcudart) + driver libcuda.
# ----------------------------------------------------------------------------
def _find(pkg_subpath, soglob):
    import nvidia  # noqa
    base = os.path.dirname(nvidia.__file__)
    hits = glob.glob(os.path.join(base, pkg_subpath, "lib", soglob))
    if not hits:
        raise RuntimeError(f"could not find {soglob} under {base}/{pkg_subpath}")
    return sorted(hits)[-1]

_NVRTC_PATH = _find("cuda_nvrtc", "libnvrtc.so*")
_CUDART_PATH = _find("cuda_runtime", "libcudart.so*")

# libnvrtc needs its builtins sibling on the loader path
os.environ["LD_LIBRARY_PATH"] = (
    os.path.dirname(_NVRTC_PATH) + ":" + os.environ.get("LD_LIBRARY_PATH", "")
)

nvrtc = ctypes.CDLL(_NVRTC_PATH)
cuda = ctypes.CDLL("libcuda.so.1")  # driver API


# ----------------------------------------------------------------------------
# Kernel source — device code copied VERBATIM from reconstruct-weights-gpu.cu
# (the dequantize_uint8 helper and the reconstruct_weights_spectral kernel).
# Algorithm unmodified; only the surrounding host wrapper differs (we use the
# Driver API from Python instead of the .cu's extern "C" host function).
# ----------------------------------------------------------------------------
_KERNEL_SRC = r"""
// NVRTC has no system include path; the kernel only needs `unsigned char`
// and `float`, so <stdint.h> from the original .cu is intentionally omitted.

#define BLOCK_SIZE 16
#define NUM_COMPONENTS 3

__device__ float dequantize_uint8(unsigned char q8, float min_val, float max_val) {
    float normalized = (float)q8 / 255.0f;
    return min_val + normalized * (max_val - min_val);
}

extern "C" __global__ void reconstruct_weights_spectral(
    const unsigned char* U_q8,
    const unsigned char* sigma_q8,
    const unsigned char* Vt_q8,
    float* W_out,
    int d_out, int d_in,
    float U_min, float U_max,
    float sigma_min, float sigma_max,
    float V_min, float V_max
) {
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;

    if (i >= d_out || j >= d_in) return;

    float w_ij = 0.0f;

    for (int k = 0; k < NUM_COMPONENTS; k++) {
        int u_idx = i * NUM_COMPONENTS + k;
        float u_ik = dequantize_uint8(U_q8[u_idx], U_min, U_max);

        float sigma_k = dequantize_uint8(sigma_q8[k], sigma_min, sigma_max);

        int v_idx = k * d_in + j;
        float v_kj = dequantize_uint8(Vt_q8[v_idx], V_min, V_max);

        w_ij += u_ik * sigma_k * v_kj;
    }

    W_out[i * d_in + j] = w_ij;
}
"""

_BLOCK = 16

# ----------------------------------------------------------------------------
# CUDA Driver API + NVRTC ctypes prototypes
# ----------------------------------------------------------------------------
def _chk_nvrtc(res, prog=None):
    if res != 0:
        msg = b"nvrtc error"
        if prog is not None:
            sz = ctypes.c_size_t()
            nvrtc.nvrtcGetProgramLogSize(prog, ctypes.byref(sz))
            log = ctypes.create_string_buffer(sz.value)
            nvrtc.nvrtcGetProgramLog(prog, log)
            msg = log.value
        raise RuntimeError(f"NVRTC failed ({res}): {msg.decode(errors='replace')}")

def _chk(res, what=""):
    if res != 0:
        errstr = ctypes.c_char_p()
        try:
            cuda.cuGetErrorString(res, ctypes.byref(errstr))
            detail = errstr.value.decode() if errstr.value else "?"
        except Exception:
            detail = "?"
        raise RuntimeError(f"CUDA driver error {res} ({detail}) at {what}")


class GpuReconstructor:
    """Compiles the kernel once (NVRTC->PTX, sm_61) and runs it on the GPU."""

    def __init__(self, arch="compute_61"):
        # --- compile source -> PTX via NVRTC ---
        prog = ctypes.c_void_p()
        _chk_nvrtc(nvrtc.nvrtcCreateProgram(
            ctypes.byref(prog), _KERNEL_SRC.encode(), b"reconstruct.cu",
            0, None, None))
        opts = [f"--gpu-architecture={arch}".encode()]
        opt_arr = (ctypes.c_char_p * len(opts))(*opts)
        res = nvrtc.nvrtcCompileProgram(prog, len(opts), opt_arr)
        _chk_nvrtc(res, prog)
        ptx_size = ctypes.c_size_t()
        nvrtc.nvrtcGetPTXSize(prog, ctypes.byref(ptx_size))
        ptx = ctypes.create_string_buffer(ptx_size.value)
        nvrtc.nvrtcGetPTX(prog, ptx)
        nvrtc.nvrtcDestroyProgram(ctypes.byref(prog))
        self.ptx = ptx

        # --- driver init / context ---
        _chk(cuda.cuInit(0), "cuInit")
        dev = ctypes.c_int()
        _chk(cuda.cuDeviceGet(ctypes.byref(dev), 0), "cuDeviceGet")
        self.ctx = ctypes.c_void_p()
        _chk(cuda.cuCtxCreate_v2(ctypes.byref(self.ctx), 0, dev), "cuCtxCreate")

        # --- load module + get kernel ---
        self.module = ctypes.c_void_p()
        _chk(cuda.cuModuleLoadData(ctypes.byref(self.module), ptx), "cuModuleLoadData")
        self.func = ctypes.c_void_p()
        _chk(cuda.cuModuleGetFunction(
            ctypes.byref(self.func), self.module, b"reconstruct_weights_spectral"),
            "cuModuleGetFunction")

    def reconstruct(self, U_q8, sigma_q8, Vt_q8, d_out, d_in,
                    U_min, U_max, sigma_min, sigma_max, V_min, V_max):
        """Run the kernel on the GPU and return W_out (d_out x d_in) float32."""
        U_q8 = np.ascontiguousarray(U_q8, dtype=np.uint8)
        sigma_q8 = np.ascontiguousarray(sigma_q8, dtype=np.uint8)
        Vt_q8 = np.ascontiguousarray(Vt_q8, dtype=np.uint8)
        W_out = np.empty(d_out * d_in, dtype=np.float32)

        dU = ctypes.c_void_p(); dS = ctypes.c_void_p()
        dV = ctypes.c_void_p(); dW = ctypes.c_void_p()
        _chk(cuda.cuMemAlloc_v2(ctypes.byref(dU), U_q8.nbytes), "alloc U")
        _chk(cuda.cuMemAlloc_v2(ctypes.byref(dS), sigma_q8.nbytes), "alloc S")
        _chk(cuda.cuMemAlloc_v2(ctypes.byref(dV), Vt_q8.nbytes), "alloc V")
        _chk(cuda.cuMemAlloc_v2(ctypes.byref(dW), W_out.nbytes), "alloc W")

        _chk(cuda.cuMemcpyHtoD_v2(dU, U_q8.ctypes.data_as(ctypes.c_void_p), U_q8.nbytes), "H2D U")
        _chk(cuda.cuMemcpyHtoD_v2(dS, sigma_q8.ctypes.data_as(ctypes.c_void_p), sigma_q8.nbytes), "H2D S")
        _chk(cuda.cuMemcpyHtoD_v2(dV, Vt_q8.ctypes.data_as(ctypes.c_void_p), Vt_q8.nbytes), "H2D V")

        c_d_out = ctypes.c_int(d_out); c_d_in = ctypes.c_int(d_in)
        fU0, fU1 = ctypes.c_float(U_min), ctypes.c_float(U_max)
        fS0, fS1 = ctypes.c_float(sigma_min), ctypes.c_float(sigma_max)
        fV0, fV1 = ctypes.c_float(V_min), ctypes.c_float(V_max)

        args = [dU, dS, dV, dW, c_d_out, c_d_in, fU0, fU1, fS0, fS1, fV0, fV1]
        arg_ptrs = (ctypes.c_void_p * len(args))(
            *[ctypes.cast(ctypes.byref(a), ctypes.c_void_p) for a in args])

        gx = (d_in + _BLOCK - 1) // _BLOCK
        gy = (d_out + _BLOCK - 1) // _BLOCK
        _chk(cuda.cuLaunchKernel(
            self.func,
            gx, gy, 1,            # grid
            _BLOCK, _BLOCK, 1,    # block
            0, None,              # shared mem, stream
            arg_ptrs, None), "launch")
        _chk(cuda.cuCtxSynchronize(), "sync")

        _chk(cuda.cuMemcpyDtoH_v2(W_out.ctypes.data_as(ctypes.c_void_p), dW, W_out.nbytes), "D2H W")

        cuda.cuMemFree_v2(dU); cuda.cuMemFree_v2(dS)
        cuda.cuMemFree_v2(dV); cuda.cuMemFree_v2(dW)
        return W_out.reshape(d_out, d_in)


# Singleton accessor
_GLOBAL = None
def get_reconstructor():
    global _GLOBAL
    if _GLOBAL is None:
        _GLOBAL = GpuReconstructor()
    return _GLOBAL


def reconstruct_layer_gpu(quantized, metadata):
    """Drop-in GPU replacement for the server's _reconstruct_layer body.

    `quantized` = {"U_q8","sigma_q8","V_q8"}, `metadata` = {d_out,d_in,rank,
    U_max,sigma_max,V_max}. Returns float32 [d_out x d_in]. Marshals the
    server's offset-128/unsigned dequant scheme into the kernel's min/max form.
    """
    u_q8 = np.ascontiguousarray(quantized["U_q8"], dtype=np.uint8)
    sigma_q8 = np.ascontiguousarray(quantized["sigma_q8"], dtype=np.uint8)
    v_q8 = np.ascontiguousarray(quantized["V_q8"], dtype=np.uint8)

    d_out = int(metadata["d_out"]); d_in = int(metadata["d_in"])
    u_max = float(metadata["U_max"])
    sigma_max = float(metadata["sigma_max"])
    v_max = float(metadata["V_max"])

    # offset-128 signed -> kernel min/max
    U_min = -128.0 / 127.0 * u_max
    V_min = -128.0 / 127.0 * v_max
    rec = get_reconstructor()
    return rec.reconstruct(
        u_q8, sigma_q8, v_q8, d_out, d_in,
        U_min, u_max,        # U range
        0.0, sigma_max,      # sigma range (unsigned)
        V_min, v_max,        # V range
    )


if __name__ == "__main__":
    # quick self-test on a synthetic layer
    rng = np.random.default_rng(0)
    d_out, d_in = 64, 96
    U_q8 = rng.integers(0, 256, size=d_out * 3, dtype=np.uint8)
    sigma_q8 = rng.integers(0, 256, size=3, dtype=np.uint8)
    V_q8 = rng.integers(0, 256, size=3 * d_in, dtype=np.uint8)
    meta = dict(d_out=d_out, d_in=d_in, rank=3,
                U_max=np.float32(0.12), sigma_max=np.float32(8.5), V_max=np.float32(0.09))
    W = reconstruct_layer_gpu(
        dict(U_q8=U_q8, sigma_q8=sigma_q8, V_q8=V_q8), meta)
    print("GPU W shape:", W.shape, "sample:", W[0, :3])
